706	function formatCount(n: number | null): string {
707	  if (n === null) return '—';
708	  if (n < 1000) return String(n);
709	  if (n < 1_000_000) return `${(n / 1000).toFixed(n < 10_000 ? 1 : 0)}k`;
710	  return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}m`;
711	}
712	
713	const styles = StyleSheet.create({
