// US-044 end-to-end probe: verifies that the Supabase Realtime subscription
// on `public.applications` filtered by `creator_id=eq.<me>` delivers UPDATE
// events under a real Marketify JWT (HS256, `app_role=creator`).
//
// Why this exists: the in-app DevRolePicker session mints a literal
// `dev-creator-token` string that the Realtime broker rejects — so the UI
// can't actually exercise the subscription end-to-end without a signed up
// creator. Per Codebase Pattern #122, this probe closes the loop: empty-
// state screenshots from the DevRolePicker session verify the subscription
// wiring doesn't crash the screen, and this script verifies the broker
// delivers UPDATE events through `supabase.realtime.setAuth` under the
// same RLS policy (`applications_creator_rw`, polcmd='*') that guards the
// in-app stream.
//
// Run modes (argv[2]):
//
//   signup       Sign up a fresh probe creator via auth-signup-creator.
//                Prints `{user_id, token}` JSON on stdout for the operator
//                to capture. NOTE — the printed JWT has the default
//                edge-function TTL (~7 days); the operator is expected to
//                delete the probe user + its cascading rows via MCP
//                execute_sql immediately after the verify phase finishes.
//
//   subscribe    Subscribe to realtime UPDATE events on `applications`
//                filtered by `creator_id=eq.<MARKETIFY_PROBE_USER_ID>`.
//                Prints "READY <user_id>" once the channel is SUBSCRIBED
//                so the operator can seed + flip an application via
//                execute_sql, then waits up to 60s for an UPDATE event
//                whose id matches MARKETIFY_PROBE_APP_ID and asserts the
//                new.status equals MARKETIFY_PROBE_EXPECTED_STATUS
//                (default 'approved'). Exit 0 on match, 2 on timeout or
//                mismatch.
//
// Env vars required for `subscribe` mode:
//   MARKETIFY_PROBE_JWT
//   MARKETIFY_PROBE_USER_ID
//   MARKETIFY_PROBE_APP_ID
//   MARKETIFY_PROBE_EXPECTED_STATUS (optional — default 'approved')
//
// Usage:
//   bun run scripts/test/probe-us044-realtime.ts signup
//   MARKETIFY_PROBE_JWT=... MARKETIFY_PROBE_USER_ID=... \
//     MARKETIFY_PROBE_APP_ID=... \
//     bun run scripts/test/probe-us044-realtime.ts subscribe

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.SUPABASE_URL;
const anonKey = process.env.SUPABASE_ANON_KEY;
if (!supabaseUrl || !anonKey) {
  console.error('SUPABASE_URL and SUPABASE_ANON_KEY are required in .env');
  process.exit(1);
}

const mode = process.argv[2];
if (mode !== 'signup' && mode !== 'subscribe') {
  console.error(
    'usage: bun run scripts/test/probe-us044-realtime.ts <signup|subscribe>',
  );
  process.exit(1);
}

if (mode === 'signup') {
  const unique = Date.now();
  const res = await fetch(`${supabaseUrl}/functions/v1/auth-signup-creator`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${anonKey}`,
      apikey: anonKey,
    },
    body: JSON.stringify({
      username: `us044_probe_${unique}`,
      tiktok_handle: `us044_probe_${unique}`,
    }),
  });
  const body = (await res.json().catch(() => null)) as
    | { token?: string; user_id?: string }
    | null;
  console.log('[signup]', res.status);
  if (res.status !== 200 || !body?.token || !body?.user_id) {
    console.error('[signup] unexpected', body);
    process.exit(1);
  }
  console.log(JSON.stringify({ user_id: body.user_id, token: body.token }));
  process.exit(0);
}

const jwt = process.env.MARKETIFY_PROBE_JWT;
const userId = process.env.MARKETIFY_PROBE_USER_ID;
const appId = process.env.MARKETIFY_PROBE_APP_ID;
const expectedStatus = process.env.MARKETIFY_PROBE_EXPECTED_STATUS ?? 'approved';

if (!jwt || !userId || !appId) {
  console.error(
    'MARKETIFY_PROBE_JWT, MARKETIFY_PROBE_USER_ID, MARKETIFY_PROBE_APP_ID are required for subscribe mode',
  );
  process.exit(1);
}

// Build a client whose HTTP fetch attaches the probe JWT on every request.
// Realtime runs on a separate websocket that doesn't go through the fetch
// wrapper — we call `realtime.setAuth(token)` explicitly below (mirrors the
// pattern in app/(creator)/applications.tsx and Codebase Pattern #105).
const probeFetch: typeof fetch = (input, init) => {
  const headers = new Headers(init?.headers);
  headers.set('Authorization', `Bearer ${jwt}`);
  return fetch(input, { ...init, headers });
};

const supabase = createClient(supabaseUrl, anonKey, {
  auth: {
    persistSession: false,
    autoRefreshToken: false,
    detectSessionInUrl: false,
  },
  global: { fetch: probeFetch },
});

await supabase.realtime.setAuth(jwt);

type EventPayload = { id?: string; status?: string };
let received: EventPayload | null = null;

const channel = supabase
  .channel(`probe-us044-${userId}`)
  .on(
    'postgres_changes',
    {
      event: 'UPDATE',
      schema: 'public',
      table: 'applications',
      filter: `creator_id=eq.${userId}`,
    },
    (payload) => {
      const next = payload.new as EventPayload;
      if (next?.id === appId) {
        received = next;
      }
    },
  )
  .subscribe((status) => {
    if (status === 'SUBSCRIBED') {
      console.log(`READY ${userId}`);
    } else if (
      status === 'CLOSED' ||
      status === 'CHANNEL_ERROR' ||
      status === 'TIMED_OUT'
    ) {
      console.error(`[channel] status=${status}`);
    }
  });

const timeoutMs = 60_000;
const started = Date.now();
while (received === null) {
  if (Date.now() - started > timeoutMs) {
    console.error('[verdict] FAIL — no UPDATE event received within 60s');
    await supabase.removeChannel(channel);
    process.exit(2);
  }
  await new Promise((r) => setTimeout(r, 200));
}

console.log('[event]', JSON.stringify(received));

if (received.status !== expectedStatus) {
  console.error(
    `[verdict] FAIL — expected new.status=${expectedStatus}, got ${received.status}`,
  );
  await supabase.removeChannel(channel);
  process.exit(2);
}

console.log(
  `[verdict] PASS — realtime UPDATE event delivered with new.status=${expectedStatus}`,
);
await supabase.removeChannel(channel);
process.exit(0);

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  Pressable,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  View,
  type StyleProp,
  type ViewStyle,
} from 'react-native';
import { router } from 'expo-router';
import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
import { SkeletonCard } from '@/components/primitives/SkeletonCard';
import { useToast } from '@/components/primitives/Toast';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import { useAuth } from '@/lib/auth';
import { getCachedToken } from '@/lib/storage';
import { supabase } from '@/lib/supabase';
import { formatRelativeTime } from '@/lib/time';
import type { Database } from '@/types/supabase';

// US-043 — Creator "My Applications" tab. Calls the `list_my_applications`
// SECURITY DEFINER RPC which joins applications → listings → users (lister
// handle) → listing_versions (snapshot title) under the caller's auth.uid
// and returns a flat shape the UI can render directly. The RPC exists
// because a plain PostgREST embed would silently null the lister handle
// (users RLS is self-only) and the version title for non-active listings
// (listing_versions RLS is gated on listing.status='active').
//
// Segments: Pending / Approved / Rejected / Cancelled per AC.
// DB enum has 6 values; withdrawn + cancelled_listing_* all bucket to
// "Cancelled" per design §3.1 label + AC's 4-segment design. Route path
// matches docs/design.md:151 canonical URL `/(creator)/applications`.
//
// US-044 extends this screen with a Supabase Realtime subscription on
// UPDATEs to `public.applications` filtered by `creator_id=me`. On status
// change we patch the affected row in state (so it visibly jumps to the
// new segment without a reload) and fire a success/error toast for the
// two decisions the AC calls out: approved and rejected. The applications
// table was added to the `supabase_realtime` publication in the companion
// migration `us_044_applications_realtime_publication`. RLS
// (`applications_creator_rw`, polcmd='*') already restricts the stream to
// the caller's own rows — the client-side filter is an additional
// throughput guard, not the security boundary.

type ApplicationStatus = Database['public']['Enums']['application_status'];
type Segment = 'pending' | 'approved' | 'rejected' | 'cancelled';
type ApplicationRow = Database['public']['Functions']['list_my_applications']['Returns'][number];

const STATUS_BUCKET: Record<ApplicationStatus, Segment> = {
  pending: 'pending',
  approved: 'approved',
  rejected: 'rejected',
  withdrawn: 'cancelled',
  cancelled_listing_edit: 'cancelled',
  cancelled_listing_closed: 'cancelled',
};

const SEGMENTS: readonly { key: Segment; label: string }[] = [
  { key: 'pending', label: 'Pending' },
  { key: 'approved', label: 'Approved' },
  { key: 'rejected', label: 'Rejected' },
  { key: 'cancelled', label: 'Cancelled' },
];

// Segmented control semantics: a11y role "tab" with single-select state.
// Chip primitive (checkbox role) is for multi-select filter rows — a
// segmented control needs single-select. Keeping this inline rather than
// promoting to a shared primitive until another screen needs it.
type SegmentControlProps = {
  active: Segment;
  onChange: (next: Segment) => void;
};

function SegmentControl({ active, onChange }: SegmentControlProps) {
  return (
    <View style={styles.segmentRow} accessibilityRole="tablist">
      {SEGMENTS.map((s) => (
        <SegmentButton
          key={s.key}
          label={s.label}
          selected={active === s.key}
          onPress={() => onChange(s.key)}
          testID={`segment-${s.key}`}
        />
      ))}
    </View>
  );
}

type SegmentButtonProps = {
  label: string;
  selected: boolean;
  onPress: () => void;
  testID?: string;
};

function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
  const bg = selected ? colors.primarySoft : colors.surface;
  const textColor = selected ? colors.primaryDeep : colors.ink;
  return (
    <Pressable
      onPress={onPress}
      accessibilityRole="tab"
      accessibilityState={{ selected }}
      accessibilityLabel={label}
      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
      testID={testID}
    >
      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
        {label}
      </Text>
    </Pressable>
  );
}

export default function Applications() {
  const { user } = useAuth();
  const userId = user?.id ?? null;
  const { show: showToast } = useToast();

  const [segment, setSegment] = useState<Segment>('pending');
  const [rows, setRows] = useState<ApplicationRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Realtime handler reads the prior status to detect real transitions
  // (no-op UPDATEs shouldn't trigger a toast). A ref mirrors `rows` so the
  // subscription callback sees the latest state without re-subscribing on
  // every list mutation.
  const rowsRef = useRef<ApplicationRow[]>([]);
  useEffect(() => {
    rowsRef.current = rows;
  }, [rows]);

  const load = useCallback(async () => {
    if (!userId) return;
    setLoading(true);
    setError(null);
    const { data, error: rpcError } = await supabase.rpc('list_my_applications');
    if (rpcError) {
      setError("Couldn't load applications.");
      setRows([]);
    } else {
      setRows(data ?? []);
    }
    setLoading(false);
  }, [userId]);

  useEffect(() => {
    void load();
  }, [load]);

  // US-044 — Subscribe to UPDATE events on the caller's own applications.
  // RLS (`applications_creator_rw`) enforces the security boundary; the
  // `creator_id=eq.<id>` filter is a client-side throughput guard so the
  // Realtime broker doesn't ship rows we'll discard. We use
  // `supabase.realtime.setAuth(token)` for the same reason as the US-036
  // pattern (Codebase Pattern #105) — websocket auth doesn't go through
  // the marketifyFetch Authorization wrapper.
  useEffect(() => {
    if (!userId) return;
    const token = getCachedToken();
    if (!token) return;
    let cancelled = false;
    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
    void supabase.realtime.setAuth(token).then(() => {
      if (cancelled) return;
      activeChannel = supabase
        .channel(`creator-applications-${userId}`)
        .on(
          'postgres_changes',
          {
            event: 'UPDATE',
            schema: 'public',
            table: 'applications',
            filter: `creator_id=eq.${userId}`,
          },
          (payload) => {
            const next = payload.new as { id?: string; status?: ApplicationStatus };
            if (!next.id || !next.status) return;
            const prior = rowsRef.current.find((r) => r.id === next.id);
            if (!prior) return;
            if (prior.status === next.status) return;
            const nextStatus = next.status;
            setRows((cur) =>
              cur.map((r) => (r.id === next.id ? { ...r, status: nextStatus } : r)),
            );
            if (nextStatus === 'approved') {
              showToast({
                message: 'Your application was approved',
                variant: 'success',
              });
            } else if (nextStatus === 'rejected') {
              showToast({
                message: 'Your application was rejected',
                variant: 'error',
              });
            }
          },
        )
        .subscribe();
    });
    return () => {
      cancelled = true;
      if (activeChannel) void supabase.removeChannel(activeChannel);
    };
  }, [userId, showToast]);

  const byBucket = useMemo(() => {
    const map: Record<Segment, ApplicationRow[]> = {
      pending: [],
      approved: [],
      rejected: [],
      cancelled: [],
    };
    for (const r of rows) {
      map[STATUS_BUCKET[r.status]].push(r);
    }
    return map;
  }, [rows]);

  const visible = byBucket[segment];

  return (
    <SafeAreaView style={styles.root}>
      <ScrollView contentContainerStyle={styles.scroll}>
        <Text style={[textStyles.display, styles.header]}>Applied</Text>
        <SegmentControl active={segment} onChange={setSegment} />

        {loading ? (
          <View style={styles.list} testID="applications-loading">
            <SkeletonCard />
            <SkeletonCard />
          </View>
        ) : error ? (
          <View style={styles.emptyBox}>
            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
          </View>
        ) : visible.length === 0 ? (
          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
            <Text style={[textStyles.body, { color: colors.ink70 }]}>
              {emptyMessageFor(segment)}
            </Text>
          </View>
        ) : (
          <View style={styles.list}>
            {visible.map((row) => (
              <ApplicationRowCard key={row.id} row={row} />
            ))}
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

function emptyMessageFor(segment: Segment): string {
  switch (segment) {
    case 'pending':
      return 'No pending applications yet. Apply from Discover.';
    case 'approved':
      return 'Nothing approved yet — keep applying.';
    case 'rejected':
      return 'No rejections here.';
    case 'cancelled':
      return 'No cancelled applications.';
  }
}

type ApplicationRowCardProps = {
  row: ApplicationRow;
  style?: StyleProp<ViewStyle>;
};

// Title fallback: prefer listings.title (current), fall back to the
// version snapshot title (what the creator originally applied against),
// then a generic. Both fields come from the RPC so both are always
// populated for rows the caller owns.
function resolveTitle(row: ApplicationRow): string {
  return row.listing_title || row.version_title || 'Untitled campaign';
}

function ApplicationRowCard({ row, style }: ApplicationRowCardProps) {
  const title = resolveTitle(row);
  const handle = row.lister_handle;
  const pillStatus: StatusPillStatus = STATUS_BUCKET[row.status];
  const relative = formatRelativeTime(new Date(row.created_at));

  const onPress = useCallback(() => {
    router.push(`/(creator)/listing/${row.listing_id}`);
  }, [row.listing_id]);

  return (
    <Pressable
      onPress={onPress}
      accessibilityRole="button"
      accessibilityLabel={`${title}${handle ? ` by @${handle}` : ''}, ${pillStatus}, applied ${relative}`}
      style={[styles.card, shadows.hard, style]}
      testID={`application-${row.id}`}
    >
      <View style={styles.cardTopRow}>
        <View style={styles.cardTitleBlock}>
          <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={2}>
            {title}
          </Text>
          {handle ? (
            <Text style={[textStyles.caption, { color: colors.ink70 }]}>@{handle}</Text>
          ) : null}
        </View>
        <StatusPill status={pillStatus} />
      </View>
      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
    </Pressable>
  );
}

