await supabase.realtime.setAuth(jwt);

type EventPayload = { id?: string; status?: string };
let received: EventPayload | null = null;

const channel = supabase
  .channel(`probe-us044-${userId}`)
  .on(
    'postgres_changes',
    {
      event: 'UPDATE',
      schema: 'public',
      table: 'applications',
      filter: `creator_id=eq.${userId}`,
    },
    (payload) => {
      const next = payload.new as EventPayload;
      if (next?.id === appId) {
        received = next;
      }
    },
  )
  .subscribe((status) => {
    if (status === 'SUBSCRIBED') {
      console.log(`READY ${userId}`);
    } else if (
      status === 'CLOSED' ||
      status === 'CHANNEL_ERROR' ||
      status === 'TIMED_OUT'
    ) {
      console.error(`[channel] status=${status}`);
    }
  });

const timeoutMs = 60_000;
const started = Date.now();
while (received === null) {
  if (Date.now() - started > timeoutMs) {
    console.error('[verdict] FAIL — no UPDATE event received within 60s');
    await supabase.removeChannel(channel);
    process.exit(2);
  }
  await new Promise((r) => setTimeout(r, 200));
}

console.log('[event]', JSON.stringify(received));

if (received.status !== expectedStatus) {
  console.error(
    `[verdict] FAIL — expected new.status=${expectedStatus}, got ${received.status}`,
  );
  await supabase.removeChannel(channel);
  process.exit(2);
}

console.log(
  `[verdict] PASS — realtime UPDATE event delivered with new.status=${expectedStatus}`,
);
await supabase.removeChannel(channel);
process.exit(0);

